import anthropic, json

client = anthropic.Anthropic()

DIMENSIONS = {
    "correctness": (
        "5=Every claim accurate. 4=Negligible error. 3=One minor error. "
        "2=Significant error. 1=Core claim is wrong."
    ),
    "actionability": (
        "5=User can act immediately. 4=Clear with minor gap. 3=Useful but requires lookup. "
        "2=Vague direction. 1=User cannot act."
    ),
    "tone": (
        "5=Warm, professional, empathetic. 4=Appropriate with minor rough edges. "
        "3=Neutral. 2=Too formal or too casual. 1=Inappropriate."
    ),
}

FLAG_THRESHOLD = 3

def evaluate_draft(question: str, draft: str) -> dict:
    scores = {}
    for dim, rubric in DIMENSIONS.items():
        prompt = (
            f"Evaluate this customer support draft on {dim}.\n"
            f"Rubric: {rubric}\n"
            f"Question: {question}\nDraft: {draft}\n"
            'Output JSON: {"score": N}'
        )
        raw = client.messages.create(
            model="claude-haiku-4-5-20251001", max_tokens=20, temperature=0.0,
            messages=[{"role": "user", "content": prompt}],
        ).content[0].text.strip()
        try:
            s, e = raw.find("{"), raw.rfind("}") + 1
            scores[dim] = int(json.loads(raw[s:e]).get("score", 3))
        except Exception:
            scores[dim] = 3
    flags = [d for d, s in scores.items() if s < FLAG_THRESHOLD]
    return {"scores": scores, "flagged": bool(flags), "flag_reasons": flags}

# Demo
q = "How do I export my data?"
for label, draft in [
    ("Good",  "Go to Settings > Export > Download CSV. The file will be emailed to you within 5 minutes."),
    ("Vague", "You can export your data from the settings area somewhere."),
]:
    result = evaluate_draft(q, draft)
    flagged = "HOLD" if result["flagged"] else "SEND"
    print(f"{label} ({flagged}): {result['scores']}")
    if result["flag_reasons"]:
        print(f"  Flag reasons: {result['flag_reasons']}")

import anthropic, json

client = anthropic.Anthropic()

# Batched multi-dimension evaluation in a single API call
BATCH_RUBRIC_TEMPLATE = """\
Evaluate the answer on ALL three dimensions below and return scores as JSON.

Dimension correctness: {correctness}
Dimension actionability: {actionability}
Dimension tone: {tone}

Question: {question}
Answer: {answer}

Output JSON only:
{{"correctness": N, "actionability": N, "tone": N}}
"""

RUBRICS = {
    "correctness": "5=Fully correct. 4=Minor error. 3=One notable error. 2=Significant error. 1=Wrong.",
    "actionability": "5=Immediately actionable. 4=Clear with minor gap. 3=Requires lookup. 2=Vague. 1=Cannot act.",
    "tone": "5=Warm, professional. 4=Appropriate. 3=Neutral. 2=Off-register. 1=Inappropriate.",
}

def batch_evaluate(question: str, answer: str) -> dict:
    """Evaluate all dimensions in a single API call."""
    prompt = BATCH_RUBRIC_TEMPLATE.format(
        question=question, answer=answer, **RUBRICS
    )
    raw = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=60,
        temperature=0.0,
        messages=[{"role": "user", "content": prompt}],
    ).content[0].text.strip()
    try:
        s, e = raw.find("{"), raw.rfind("}") + 1
        return json.loads(raw[s:e])
    except json.JSONDecodeError:
        return {"correctness": 3, "actionability": 3, "tone": 3}

# 1 API call instead of 3
scores = batch_evaluate(
    question="How do I cancel?",
    answer="Go to Settings > Billing > Cancel Subscription. Access continues until period end.",
)
print(scores)  # {"correctness": 5, "actionability": 5, "tone": 4}
